export default Accounting;

import React, { useState, useMemo } from 'react';
import { MaintenanceTask, Property, MaintenanceStatus } from '../types';
import { getMaintenanceAdvice } from '../services/geminiService';
import { COLORS } from '../constants';

interface MaintenanceProps {
  tasks: MaintenanceTask[];
  setTasks: React.Dispatch<React.SetStateAction<MaintenanceTask[]>>;
  properties: Property[];
}

const STATUS_OPTIONS: (MaintenanceStatus | 'All')[] = [
  'All',
  'Identified',
  'Assessing',
  'Quote',
  'Tech Review',
  'Approved by Tech',
  'Owner Review',
  'Approved by Owner',
  'Shop Materials',
  'Coordinate',
  'Scheduled',
  'Complete'
];

const getStatusColor = (status: MaintenanceStatus) => {
  switch (status) {
    case 'Identified': return 'bg-slate-100 text-slate-700';
    case 'Assessing': return 'bg-blue-100 text-blue-700';
    case 'Quote': return 'bg-amber-100 text-amber-700';
    case 'Tech Review': return 'bg-[#87a3a320] text-[#87a3a3]';
    case 'Approved by Tech': return 'bg-[#87a3a340] text-[#87a3a3]';
    case 'Owner Review': return 'bg-purple-100 text-purple-700';
    case 'Approved by Owner': return 'bg-purple-200 text-purple-800';
    case 'Shop Materials': return 'bg-cyan-100 text-cyan-700';
    case 'Coordinate': return 'bg-emerald-50 text-emerald-700';
    case 'Scheduled': return 'bg-emerald-100 text-emerald-700';
    case 'Complete': return 'bg-[#87a3a3] text-white';
    default: return 'bg-slate-100 text-slate-700';
  }
};

const Maintenance: React.FC<MaintenanceProps> = ({ tasks, setTasks, properties }) => {
  const [selectedTask, setSelectedTask] = useState<MaintenanceTask | null>(null);
  const [advice, setAdvice] = useState<string>('');
  const [isLoadingAdvice, setIsLoadingAdvice] = useState(false);
  const [filterStatus, setFilterStatus] = useState<MaintenanceStatus | 'All'>('All');

  const counts = useMemo(() => {
    const acc: Record<string, number> = { All: tasks.length };
    tasks.forEach(task => {
      acc[task.status] = (acc[task.status] || 0) + 1;
    });
    return acc;
  }, [tasks]);

  const filteredTasks = useMemo(() => {
    if (filterStatus === 'All') return tasks;
    return tasks.filter(t => t.status === filterStatus);
  }, [tasks, filterStatus]);

  const fetchAdvice = async (task: MaintenanceTask) => {
    setSelectedTask(task);
    setIsLoadingAdvice(true);
    const result = await getMaintenanceAdvice(task.title, task.description);
    setAdvice(result || "Could not get advice.");
    setIsLoadingAdvice(false);
  };

  const updateStatus = (taskId: string, newStatus: MaintenanceStatus) => {
    setTasks(prev => prev.map(t => t.id === taskId ? { ...t, status: newStatus } : t));
    if (selectedTask?.id === taskId) {
      setSelectedTask(prev => prev ? { ...prev, status: newStatus } : null);
    }
  };

  const updateDateField = (taskId: string, field: 'assessmentDate' | 'scheduledDate', value: string) => {
    setTasks(prev => prev.map(t => t.id === taskId ? { ...t, [field]: value } : t));
    if (selectedTask?.id === taskId) {
      setSelectedTask(prev => prev ? { ...prev, [field]: value } : null);
    }
  };

  return (
    <div className="space-y-8 animate-fadeIn">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
        <div>
          <h2 className="text-4xl font-black text-slate-800 tracking-tight">Maintenance Pipeline</h2>
          <p className="text-slate-500 font-medium">Coordinate logistics and upkeep across all assets.</p>
        </div>
        <button className="px-8 py-4 bg-[#87a3a3] text-white rounded-[24px] font-black text-xs uppercase tracking-widest shadow-xl shadow-[#87a3a340] hover:bg-[#6b8686] hover:translate-y-[-2px] transition-all flex-shrink-0">
          + Create Job
        </button>
      </div>

      {/* Filter Bar */}
      <div className="flex overflow-x-auto pb-6 gap-3 no-scrollbar scroll-smooth">
        {STATUS_OPTIONS.map((opt) => (
          <button
            key={opt}
            onClick={() => setFilterStatus(opt)}
            className={`px-5 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest whitespace-nowrap transition-all border-2 flex items-center gap-3 ${
              filterStatus === opt 
                ? 'bg-[#87a3a3] border-[#87a3a3] text-white shadow-lg' 
                : 'bg-white border-slate-100 text-slate-400 hover:border-[#87a3a320] hover:text-slate-600'
            }`}
          >
            {opt}
            <span className={`px-2 py-0.5 rounded-lg text-[9px] ${
              filterStatus === opt ? 'bg-white/20 text-white' : 'bg-slate-50 text-slate-400'
            }`}>
              {counts[opt] || 0}
            </span>
          </button>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
        {/* Task List */}
        <div className="space-y-6 max-h-[800px] overflow-y-auto pr-4 custom-scrollbar">
          {filteredTasks.length > 0 ? (
            filteredTasks.map(task => (
              <div 
                key={task.id} 
                className={`bg-white p-7 rounded-[32px] shadow-sm border-2 transition-all cursor-pointer group ${
                  selectedTask?.id === task.id ? 'border-[#87a3a3] ring-4 ring-[#87a3a310]' : 'border-slate-50 hover:border-slate-200'
                }`}
