import React, { useState, useMemo } from 'react';
import { Lease, Property } from '../types';

interface LeasesProps {
  leases: Lease[];
  setLeases: React.Dispatch<React.SetStateAction<Lease[]>>;
  properties: Property[];
}

const Leases: React.FC<LeasesProps> = ({ leases, setLeases, properties }) => {
  const [filterStatus, setFilterStatus] = useState<Lease['status'] | 'All'>('All');

  const filteredLeases = useMemo(() => {
    if (filterStatus === 'All') return leases;
    return leases.filter(l => l.status === filterStatus);
  }, [leases, filterStatus]);

  const getStatusStyle = (status: Lease['status']) => {
    switch (status) {
      case 'Active': return 'bg-emerald-50 text-emerald-600';
      case 'Expiring': return 'bg-amber-50 text-amber-600';
      case 'Terminated': return 'bg-rose-50 text-rose-600';
      case 'Pending': return 'bg-slate-50 text-slate-400';
      default: return 'bg-slate-50 text-slate-400';
    }
  };

  return (
    <div className="space-y-8 animate-fadeIn">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
        <div>
