                <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Asset Location</th>
                <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Contractual Term</th>
                <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Monthly Commitment</th>
                <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Status</th>
                <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Execution</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredLeases.map(lease => (
                <tr key={lease.id} className="hover:bg-slate-50/50 transition-all group">
                  <td className="px-8 py-6">
                    <div className="font-black text-slate-800 group-hover:text-[#87a3a3] transition-colors">{lease.tenantName}</div>
                    <div className="text-[9px] font-black text-slate-300 uppercase tracking-widest">ID: {lease.id}</div>
                  </td>
                  <td className="px-8 py-6">
                    <div className="text-sm font-bold text-slate-600">
                      {properties.find(p => p.id === lease.propertyId)?.name || 'Lot 202 Unit'}
                    </div>
                  </td>
                  <td className="px-8 py-6">
                    <div className="text-xs font-bold text-slate-400 uppercase tracking-tighter">{lease.startDate} <span className="mx-2 text-slate-200">—</span> {lease.endDate}</div>
                  </td>
                  <td className="px-8 py-6 font-black text-[#87a3a3]">
                    ${lease.monthlyRent.toLocaleString()}<span className="text-[9px] uppercase tracking-widest text-slate-300 ml-1">/ mo</span>
                  </td>
                  <td className="px-8 py-6">
                    <span className={`px-3 py-1.5 rounded-xl text-[9px] font-black uppercase tracking-widest ${getStatusStyle(lease.status)}`}>
                      {lease.status}
                    </span>
                  </td>
                  <td className="px-8 py-6 text-right">
                    <button className="text-[10px] font-black uppercase tracking-widest text-slate-300 hover:text-[#87a3a3] transition-colors border border-slate-100 px-4 py-2 rounded-xl hover:bg-slate-50">Legal Audit</button>
                  </td>
                </tr>
              ))}
              {filteredLeases.length === 0 && (
                <tr>
                  <td colSpan={6} className="px-8 py-20 text-center">
                    <p className="text-slate-300 font-bold italic">No contract matching the criteria "{filterStatus}" found.</p>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

