import { GoogleGenAI } from "@google/genai";
import { logger } from '@/core/lib/logger';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const handleError = (error: any, correlationId?: string, operation?: string) => {
    const errorMessage = error instanceof Error ? error.message : 'An unknown error occurred';
    logger.error(`Gemini API Error in ${operation}`, {
      correlationId,
      error: errorMessage,
    });
    // Do not leak detailed error info to the client-side UI, but provide the correlation ID for debugging.
    return `An error occurred during ${operation}. Please check logs for Correlation ID: ${correlationId}.`;
};

export async function getMaintenanceAdvice(taskTitle: string, description: string, correlationId: string) {
  const operation = 'getMaintenanceAdvice';
  logger.info('Starting operation', { correlationId, operation, taskTitle });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `As an expert property manager, provide quick advice (max 100 words) for this maintenance task: ${taskTitle}. Description: ${description}. Focus on cost efficiency and safety.`,
    });
    logger.info('Operation successful', { correlationId, operation });
    return response.text;
  } catch (error) {
    return handleError(error, correlationId, operation);
  }
}

export async function analyzeAccounting(data: string, correlationId: string) {
  const operation = 'analyzeAccounting';
  logger.info('Starting operation', { correlationId, operation });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Analyze the following accounting data from a property management business and detect anomalies or suggest financial improvements. Data: ${data}. Respond concisely and professionally in English.`,
    });
    logger.info('Operation successful', { correlationId, operation });
    return response.text;
  } catch (error) {
    return handleError(error, correlationId, operation);
  }
}

export async function checkApiConnection(correlationId: string): Promise<boolean> {
  const operation = 'checkApiConnection';
  logger.info('Starting operation', { correlationId, operation });

  try {
    await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: 'hello',
    });
    logger.info('Operation successful', { correlationId, operation });
    return true; // Success
  } catch (error) {
    const errorMessage = error instanceof Error ? error.message : 'An unknown error occurred';
    logger.error(`Gemini API Error in ${operation}`, {
      correlationId,
      error: errorMessage,
    });
    return false; // Failure
  }
}

