              filterStatus === opt 
                ? 'bg-[#87a3a3] border-[#87a3a3] text-white shadow-lg' 
                : 'bg-white border-slate-100 text-slate-300 hover:border-[#87a3a320] hover:text-slate-500'
            }`}
