import React, { createContext, useState, useContext, ReactNode } from 'react';
import { UserRole, USER_ROLES } from './roles';

interface User {
  id: string;
  name: string;
  role: UserRole;
}

interface AuthContextType {
  user: User | null;
  loginAs: (role: UserRole) => void;
}

const mockUsers: Record<UserRole, User> = {
  [USER_ROLES.Admin]: { id: 'admin-01', name: 'Admin User', role: USER_ROLES.Admin },
  [USER_ROLES.Staff]: { id: 'staff-01', name: 'Staff Member', role: USER_ROLES.Staff },
  [USER_ROLES.Tenant]: { id: 'tenant-01', name: 'Tenant Resident', role: USER_ROLES.Tenant },
};

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  // Default to Staff role for initial view
  const [user, setUser] = useState<User | null>(mockUsers.Staff);

  const loginAs = (role: UserRole) => {
    const mockUser = mockUsers[role];
    if (mockUser) {
      setUser(mockUser);
    }
  };

  return (
    <AuthContext.Provider value={{ user, loginAs }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = (): AuthContextType => {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

import React, { createContext, useState, useContext, ReactNode, useEffect } from 'react';
import en from './locales/en.json';
import es from './locales/es.json';

type Locale = 'en' | 'es';

const translations: Record<Locale, any> = { en, es };

interface I18nContextType {
  locale: Locale;
  setLocale: (locale: Locale) => void;
  t: (key: string) => string;
}

const I18nContext = createContext<I18nContextType | undefined>(undefined);

const getNestedTranslation = (obj: any, key: string): string => {
  return key.split('.').reduce((o, i) => (o ? o[i] : key), obj);
};

export const I18nProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [locale, setLocale] = useState<Locale>('en');

  useEffect(() => {
    // Default language selection strategy
    const browserLang = navigator.language.split('-')[0];
    if (browserLang === 'es') {
      setLocale('es');
    }
  }, []);

  const t = (key: string): string => {
    const translation = getNestedTranslation(translations[locale], key);
    return translation || key; // Fallback to key if not found
  };

  return (
    <I18nContext.Provider value={{ locale, setLocale, t }}>
      {children}
    </I18nContext.Provider>
  );
};

export const useTranslation = (): I18nContextType => {
  const context = useContext(I18nContext);
  if (context === undefined) {
    throw new Error('useTranslation must be used within an I18nProvider');
  }
  return context;
};

