import React, { ReactNode } from 'react';
import { useAuth } from '@/core/auth/AuthContext';
import { UserRole } from '@/core/auth/roles';
import { useTranslation } from '@/core/i18n/I18nContext';

interface ProtectedContentProps {
  roles: UserRole[];
  children: ReactNode;
}

const ProtectedContent: React.FC<ProtectedContentProps> = ({ roles, children }) => {
  const { user } = useAuth();
  const { t } = useTranslation();

  if (!user || !roles.includes(user.role)) {
    // For inline elements like sidebar links, we render nothing.
    // For larger page content, we could show an "Unauthorized" component.
    return null;
  }

  return <>{children}</>;
};

export default ProtectedContent;

import React from 'react';
import { useAuth } from '@/core/auth/AuthContext';
import { useTranslation } from '@/core/i18n/I18nContext';
import { USER_ROLES, UserRole } from '@/core/auth/roles';
import ProtectedContent from '@/shared/ui/ProtectedContent';

const Settings: React.FC = () => {
  const { user, loginAs } = useAuth();
  const { locale, setLocale, t } = useTranslation();

  const handleRoleChange = (role: UserRole) => {
    loginAs(role);
  };

  return (
    <div className="space-y-8 animate-fadeIn">
      <div>
        <h2 className="text-4xl font-black text-slate-500 tracking-tight">{t('settings.title')}</h2>
        <p className="text-slate-400 font-medium">{t('settings.description')}</p>
      </div>

      <div className="bg-white rounded-[32px] shadow-sm border border-slate-100 p-10 space-y-8">

        {/* Language Selection */}
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 p-6 bg-slate-50 rounded-2xl">
          <div>
            <h3 className="font-bold text-slate-600">{t('settings.language')}</h3>
            <p className="text-sm text-slate-400 mt-1">
              Select your preferred language for the user interface.
            </p>
          </div>
          <div className="flex gap-2 bg-white p-1.5 rounded-2xl border border-slate-200">
            <button 
              onClick={() => setLocale('en')}
              className={`px-6 py-2 font-black text-xs uppercase tracking-widest rounded-xl transition-all ${
                locale === 'en' ? 'bg-[#87a3a3] text-white shadow-sm' : 'text-slate-400 hover:bg-slate-100'
              }`}>
              English
            </button>
            <button 
              onClick={() => setLocale('es')}
              className={`px-6 py-2 font-black text-xs uppercase tracking-widest rounded-xl transition-all ${
                locale === 'es' ? 'bg-[#87a3a3] text-white shadow-sm' : 'text-slate-400 hover:bg-slate-100'
              }`}>
              Español
            </button>
          </div>
        </div>

        {/* Role Simulation */}
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 p-6 bg-slate-50 rounded-2xl">
          <div>
            <h3 className="font-bold text-slate-600">{t('settings.role')}</h3>
            <p className="text-sm text-slate-400 mt-1">
              Simulate different user roles to test access control.
            </p>
          </div>
          <div className="flex gap-2 bg-white p-1.5 rounded-2xl border border-slate-200">
            {(Object.values(USER_ROLES)).map(role => (
              <button
                key={role}
                onClick={() => handleRoleChange(role)}
                className={`px-6 py-2 font-black text-xs uppercase tracking-widest rounded-xl transition-all ${
                  user?.role === role ? 'bg-[#87a3a3] text-white shadow-sm' : 'text-slate-400 hover:bg-slate-100'
                }`}
              >
                {role}
              </button>
            ))}
          </div>
        </div>

        {/* RBAC Demonstration */}
        <ProtectedContent roles={[USER_ROLES.Admin]}>
          <div className="border-2 border-dashed border-red-200 bg-red-50 p-8 rounded-3xl animate-fadeIn">
            <h3 className="text-lg font-black text-red-500">{t('settings.admin_panel_title')}</h3>
            <p className="text-sm text-red-400 mt-1 mb-6">
              {t('settings.admin_panel_desc')}
            </p>
            <button className="px-6 py-3 bg-red-500 text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-lg shadow-red-500/20 hover:bg-red-600 transition-all">
              {t('settings.admin_panel_button')}
            </button>
          </div>
        </ProtectedContent>

      </div>
    </div>
  );
};

export default Settings;

import React, { useState, useEffect } from 'react';
import { checkApiConnection } from '@/core/services/geminiService';

type Status = 'checking' | 'ok' | 'error';

const StatusIndicator: React.FC<{ status: Status }> = ({ status }) => {
  const styles = {
    checking: {
      dot: 'bg-yellow-400 animate-pulse',
      text: 'text-yellow-500',
      message: 'Checking...',
    },
    ok: {
      dot: 'bg-emerald-500',
      text: 'text-emerald-600',
      message: 'Operational',
    },
    error: {
      dot: 'bg-red-500',
      text: 'text-red-600',
      message: 'Error Detected',
    },
  };

  const current = styles[status];

  return (
    <div className="flex items-center gap-3">
      <div className={`w-3 h-3 rounded-full ${current.dot}`}></div>
      <span className={`font-black text-sm uppercase tracking-widest ${current.text}`}>
        {current.message}
      </span>
    </div>
  );
};

const SystemStatus: React.FC = () => {
  const [apiKeyStatus, setApiKeyStatus] = useState<Status>('checking');
  const [apiConnectionStatus, setApiConnectionStatus] = useState<Status>('checking');

  useEffect(() => {
    // Check 1: API Key Presence
    if (process.env.API_KEY && process.env.API_KEY.length > 10) {
      setApiKeyStatus('ok');
    } else {
      setApiKeyStatus('error');
    }

    // Check 2: API Connectivity
    const verifyConnection = async () => {
      const correlationId = crypto.randomUUID();
      const isConnected = await checkApiConnection(correlationId);
      setApiConnectionStatus(isConnected ? 'ok' : 'error');
    };

    verifyConnection();
  }, []);

  return (
    <>
      <div className="space-y-8 animate-fadeIn">
        <div>
          <h2 className="text-4xl font-black text-slate-500 tracking-tight">System Status</h2>
          <p className="text-slate-400 font-medium">Real-time diagnostics of core application services.</p>
        </div>

        <div className="bg-white rounded-[32px] shadow-sm border border-slate-100 p-10 space-y-8">
          {/* API Key Check */}
          <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 p-6 bg-slate-50 rounded-2xl">
            <div>
              <h3 className="font-bold text-slate-600">Environment Configuration</h3>
              <p className="text-sm text-slate-400 mt-1">
                Verifies that the Gemini API key is loaded from the <code>.env</code> file correctly.
              </p>
            </div>
            <StatusIndicator status={apiKeyStatus} />
          </div>

          {/* API Connection Check */}
          <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 p-6 bg-slate-50 rounded-2xl">
            <div>
              <h3 className="font-bold text-slate-600">Gemini API Connectivity</h3>
              <p className="text-sm text-slate-400 mt-1">
                Performs a live test call to ensure the API is reachable and the key is valid.
              </p>
            </div>
            <StatusIndicator status={apiConnectionStatus} />
          </div>

        </div>
      </div>
    </>
  );
};

export default SystemStatus;

