import React, { Component, ErrorInfo, ReactNode } from 'react';
import { logger } from '@/core/lib/logger';

interface Props {
  children?: ReactNode;
}

interface State {
  hasError: boolean;
}

class ErrorBoundary extends Component<Props, State> {
  // Fix: Replaced the constructor-based state initialization with a class property.
  // This is a more modern and concise syntax and resolves the type inference issue where
  // `this.state` and `this.props` were not being recognized on the component instance.
  state: State = {
    hasError: false,
  };

  static getDerivedStateFromError(_: Error): State {
    // Update state so the next render will show the fallback UI.
    return { hasError: true };
  }

  componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    logger.error('Uncaught error in component', {
      error: {
        message: error.message,
        stack: error.stack,
      },
      componentStack: errorInfo.componentStack,
    });
  }

  render() {
    if (this.state.hasError) {
      return (
        <div className="flex flex-col items-center justify-center min-h-screen bg-slate-50 text-center p-8">
          <h1 className="text-4xl font-black text-red-500 mb-4">System Malfunction</h1>
