import React, { createContext, useState, useContext, ReactNode, useEffect } from 'react';

type Locale = 'en' | 'es';

// This will be populated asynchronously.
const translations: Record<Locale, any> = { en: {}, es: {} };

interface I18nContextType {
  locale: Locale;
  setLocale: (locale: Locale) => void;
  t: (key: string) => string;
}

const I18nContext = createContext<I18nContextType | undefined>(undefined);

const getNestedTranslation = (obj: any, key: string): string => {
  return key.split('.').reduce((o, i) => (o ? o[i] : key), obj);
};

export const I18nProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [locale, setLocale] = useState<Locale>('en');
  const [isLoaded, setIsLoaded] = useState(false);

  useEffect(() => {
    // Default language selection strategy
    const browserLang = navigator.language.split('-')[0];
    if (browserLang === 'es') {
      setLocale('es');
    }

    const loadTranslations = async () => {
      try {
        const [enResponse, esResponse] = await Promise.all([
          fetch('./core/i18n/locales/en.json'),
          fetch('./core/i18n/locales/es.json'),
        ]);
        translations.en = await enResponse.json();
        translations.es = await esResponse.json();
      } catch (error) {
        console.error('Failed to load translation files:', error);
        // Minimal fallbacks to prevent crashing if fetch fails.
        translations.en = { sidebar: {} };
        translations.es = { sidebar: {} };
      } finally {
        setIsLoaded(true);
      }
    };

    loadTranslations();
  }, []); // Empty dependency array ensures this runs only once on mount.

  const t = (key: string): string => {
    const translation = getNestedTranslation(translations[locale], key);
    return translation || key; // Fallback to key if not found.
  };

  // Render nothing until translations are fetched to avoid a flash of untranslated content.
  if (!isLoaded) {
    return null;
  }

  return (
    <I18nContext.Provider value={{ locale, setLocale, t }}>
      {children}
    </I18nContext.Provider>
  );
};

export const useTranslation = (): I18nContextType => {
  const context = useContext(I18nContext);
  if (context === undefined) {
    throw new Error('useTranslation must be used within an I18nProvider');
  }
  return context;
};

import React, { Component, ErrorInfo, ReactNode } from 'react';
import { logger } from '@/core/lib/logger';

interface Props {
  children?: ReactNode;
}

interface State {
  hasError: boolean;
}

class ErrorBoundary extends Component<Props, State> {
  // Fix: Reverted state initialization to use a constructor.
  // The class property syntax can sometimes cause issues with type inference for `this.props` in certain toolchains.
  // Using a constructor is a more robust way to ensure the component's state and props are correctly initialized.
  constructor(props: Props) {
    super(props);
    this.state = {
      hasError: false,
    };
  }

  static getDerivedStateFromError(_: Error): State {
    // Update state so the next render will show the fallback UI.
    return { hasError: true };
  }

  componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    logger.error('Uncaught error in component', {
      error: {
        message: error.message,
        stack: error.stack,
      },
      componentStack: errorInfo.componentStack,
    });
  }

  render() {
    if (this.state.hasError) {
      return (
        <div className="flex flex-col items-center justify-center min-h-screen bg-slate-50 text-center p-8">
          <h1 className="text-4xl font-black text-red-500 mb-4">System Malfunction</h1>
